function getId(e){const t=e.match(/^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/);return t&&11===t[2].length?t[2]:null}function removeVideos(e){let t=$("#removeVideo").val();t=t+"/"+e,$("#removeVideo").val(t),$("#video-item-"+e).hide()}$("#addLink").on("click",function(e){let t=$("#link").val();if(""!=t&&-1!=t.indexOf("youtube.com")){let e=getId(t);$("#youtube").append('<div class="col-md-4 youtube-item card-iframe-item img-item'+$.now()+'" data-id="'+$.now()+'"><button type="button" class="close delete-link-iframe" aria-label="ลบไฟล์นี้"><span aria-hidden="true">&times;</span></button><iframe width="100%" height="200" src="https://www.youtube.com/embed/'+e+'" frameborder="0" allowfullscreen=""></iframe> <input type="hidden" name="link[]" value="https://www.youtube.com/embed/'+e+'"></div>'),$("#link").val("")}else alert("ลิงค์ : "+t+" ไม่ถูกต้อง!")}),$(document).on("click","button.delete-link-iframe",function(){let e=$(this).parent("div").attr("data-id");$(".img-item"+e).remove()});